{
  "name": "Multi-calendar Property Management",
  "description": "An Airbnb-style multi-calendar dashboard to manage properties, sync iCal bookings from Airbnb, and visualize occupancy across rooms using Google Sheets as a backend.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Booking {
  start: string; // ISO format or YYYY-MM-DD
  end: string;   // ISO format or YYYY-MM-DD
  guestName?: string;
  status?: string;
}

export interface Room {
  id: string;
  name: string;
  building: string;
  type: string;
  icalLink: string;
  bookings: Booking[];
}

export interface ApiResponse {
  status: 'success' | 'error';
  data?: Room[];
  message?: string;
}

/**
 * GOOGLE APPS SCRIPT - BACKEND CODE
 * Copy this into a new project at script.google.com
 */

const SPREADSHEET_ID = SpreadsheetApp.getActiveSpreadsheet() ? SpreadsheetApp.getActiveSpreadsheet().getId() : "YOUR_SPREADSHEET_ID_HERE";
const SHEET_NAME = "Rooms";

function doGet(e) {
  try {
    const rooms = getRoomsData();
    return ContentService.createTextOutput(JSON.stringify({ status: "success", data: rooms }))
      .setMimeType(ContentService.MimeType.JSON);
  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: error.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

function doPost(e) {
  try {
    const params = JSON.parse(e.postData.contents);
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const sheet = ss.getSheetByName(SHEET_NAME) || ss.insertSheet(SHEET_NAME);

    // Header check
    if (sheet.getLastRow() === 0) {
      sheet.appendRow(["ID", "Name", "Building", "Type", "iCalLink"]);
    }

    const id = Utilities.getUuid();
    sheet.appendRow([id, params.name, params.building, params.type, params.icalLink]);

    return ContentService.createTextOutput(JSON.stringify({ status: "success", id: id }))
      .setMimeType(ContentService.MimeType.JSON);
  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: error.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

function getRoomsData() {
  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  const sheet = ss.getSheetByName(SHEET_NAME);
  if (!sheet) return [];

  const data = sheet.getDataRange().getValues();
  const headers = data.shift();

  return data.map(row => {
    const room = {
      id: row[0],
      name: row[1],
      building: row[2],
      type: row[3],
      icalLink: row[4],
      bookings: []
    };

    if (room.icalLink) {
      room.bookings = fetchAndParseIcal(room.icalLink);
    }

    return room;
  });
}

function fetchAndParseIcal(url) {
  try {
    const response = UrlFetchApp.fetch(url);
    const icalContent = response.getContentText();
    const events = [];

    // Very basic iCal parser for DTSTART and DTEND
    const veventMatches = icalContent.split("BEGIN:VEVENT");
    veventMatches.shift(); // Remove content before first VEVENT

    veventMatches.forEach(eventBlock => {
      const startMatch = eventBlock.match(/DTSTART(?:;VALUE=DATE)?:(\d{8}(?:T\d{6}Z?)?)/);
      const endMatch = eventBlock.match(/DTEND(?:;VALUE=DATE)?:(\d{8}(?:T\d{6}Z?)?)/);
      const summaryMatch = eventBlock.match(/SUMMARY:(.*)/);

      if (startMatch && endMatch) {
        events.push({
          start: formatDateString(startMatch[1]),
          end: formatDateString(endMatch[1]),
          guestName: summaryMatch ? summaryMatch[1].trim() : "Reserved"
        });
      }
    });

    return events;
  } catch (e) {
    console.error("Error fetching iCal:", e);
    return [];
  }
}

function formatDateString(str) {
  // Converts 20231025 to 2023-10-25
  const y = str.substring(0, 4);
  const m = str.substring(4, 6);
  const d = str.substring(6, 8);
  return `${y}-${m}-${d}`;
}

import { ApiResponse, Room } from '../types';

// NOTE: Replace this with your actual Google Apps Script Web App URL after deployment
const GAS_WEB_APP_URL = 'https://script.google.com/macros/s/AKfycbyR6m8q_L7u5T1F6A1q2z3x4c5v6b7n8m9/exec'; 

export async function fetchRooms(): Promise<Room[]> {
  try {
    // We use a mock delay for UI demonstration if URL isn't set
    if (GAS_WEB_APP_URL.includes('AKfycbyR')) {
        console.warn("Using mock data because GAS_WEB_APP_URL is not configured.");
        return getMockData();
    }

    const response = await fetch(GAS_WEB_APP_URL);
    const result: ApiResponse = await response.json();
    if (result.status === 'success' && result.data) {
      return result.data;
    }
    throw new Error(result.message || 'Failed to fetch rooms');
  } catch (error) {
    console.error("API Error:", error);
    return getMockData(); // Fallback to mock for UI development
  }
}

export async function addRoom(roomData: Partial<Room>): Promise<boolean> {
  try {
     if (GAS_WEB_APP_URL.includes('AKfycbyR')) {
        console.log("Mock add room:", roomData);
        return true;
    }
    const response = await fetch(GAS_WEB_APP_URL, {
      method: 'POST',
      body: JSON.stringify(roomData),
      headers: {
        'Content-Type': 'text/plain;charset=utf-8',
      },
      mode: 'no-cors' // Google Script requires no-cors for POST sometimes or specific redirect handling
    });
    return true; // no-cors doesn't allow reading body, assume success if no error thrown
  } catch (error) {
    console.error("API Error adding room:", error);
    return false;
  }
}

