import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  Plus, 
  Search, 
  ChevronLeft, 
  ChevronRight, 
  Filter, 
  ExternalLink, 
  X,
  Loader2,
  Calendar as CalendarIcon,
  Home
} from 'lucide-react';
import { 
  format, 
  addDays, 
  startOfDay, 
  isSameDay, 
  isWithinInterval, 
  differenceInDays, 
  startOfMonth,
  eachDayOfInterval,
  endOfMonth,
  isWeekend
} from 'date-fns';
import { Room, Booking } from './types';
import { fetchRooms, addRoom } from './services/api';
import { 
  AIRBNB_ICON, 
  CALENDAR_DAYS_COUNT, 
  DAY_COLUMN_WIDTH, 
  SIDEBAR_WIDTH 
} from './constants';

const App: React.FC = () => {
  const [rooms, setRooms] = useState<Room[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentDate, setCurrentDate] = useState(startOfDay(new Date()));
  const [filterBuilding, setFilterBuilding] = useState<string>('All');
  const [filterType, setFilterType] = useState<string>('All');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Timeline scrolling ref
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const data = await fetchRooms();
    setRooms(data);
    setLoading(false);
  };

  const days = useMemo(() => {
    return eachDayOfInterval({
      start: currentDate,
      end: addDays(currentDate, CALENDAR_DAYS_COUNT - 1)
    });
  }, [currentDate]);

  const buildings = useMemo(() => {
    const b = Array.from(new Set(rooms.map(r => r.building)));
    return ['All', ...b];
  }, [rooms]);

  const types = useMemo(() => {
    const t = Array.from(new Set(rooms.map(r => r.type)));
    return ['All', ...t];
  }, [rooms]);

  const filteredRooms = useMemo(() => {
    return rooms.filter(room => {
      const matchesBuilding = filterBuilding === 'All' || room.building === filterBuilding;
      const matchesType = filterType === 'All' || room.type === filterType;
      const matchesSearch = room.name.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesBuilding && matchesType && matchesSearch;
    });
  }, [rooms, filterBuilding, filterType, searchTerm]);

  const handlePrevDays = () => setCurrentDate(prev => addDays(prev, -7));
  const handleNextDays = () => setCurrentDate(prev => addDays(prev, 7));
  const handleToday = () => setCurrentDate(startOfDay(new Date()));

  return (
    <div className="flex flex-col h-screen bg-white">
      {/* Header */}
      <header className="border-b px-6 py-3 flex items-center justify-between bg-white sticky top-0 z-50">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 text-[#FF385C] font-bold text-xl">
             <CalendarIcon className="w-6 h-6" />
             <span>CalendarHost</span>
          </div>

          <div className="ml-8 flex items-center gap-2 bg-gray-100 rounded-full px-4 py-2 border focus-within:ring-2 ring-gray-200 transition-all">
            <Search className="w-4 h-4 text-gray-500" />
            <input 
              type="text" 
              placeholder="Search rooms..." 
              className="bg-transparent outline-none text-sm w-48"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-[#FF385C] hover:bg-[#E31C5F] text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 shadow-sm transition-colors"
          >
            <Plus className="w-4 h-4" />
            Add Room
          </button>
        </div>
      </header>

      {/* Filters & Navigation */}
      <div className="px-6 py-3 border-b bg-white flex flex-wrap items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
             <span className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Building:</span>
             <select 
              value={filterBuilding} 
              onChange={(e) => setFilterBuilding(e.target.value)}
              className="border rounded-md px-2 py-1 text-sm bg-white outline-none focus:border-gray-400"
             >
               {buildings.map(b => <option key={b} value={b}>{b}</option>)}
             </select>
          </div>
          <div className="flex items-center gap-2">
             <span className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Type:</span>
             <select 
              value={filterType} 
              onChange={(e) => setFilterType(e.target.value)}
              className="border rounded-md px-2 py-1 text-sm bg-white outline-none focus:border-gray-400"
             >
               {types.map(t => <option key={t} value={t}>{t}</option>)}
             </select>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button onClick={handlePrevDays} className="p-2 hover:bg-gray-100 rounded-full transition-colors border shadow-sm">
            <ChevronLeft className="w-4 h-4" />
          </button>
          <button 
            onClick={handleToday}
            className="px-4 py-1.5 border rounded-full text-sm font-medium hover:bg-gray-50 transition-colors shadow-sm"
          >
            Today
          </button>
          <button onClick={handleNextDays} className="p-2 hover:bg-gray-100 rounded-full transition-colors border shadow-sm">
            <ChevronRight className="w-4 h-4" />
          </button>
          <div className="ml-2 font-semibold text-gray-700">
            {format(days[0], 'MMMM yyyy')}
          </div>
        </div>
      </div>

      {/* Multi-Calendar View */}
      <div className="flex-1 overflow-hidden relative flex flex-col">
        {loading ? (
          <div className="flex-1 flex items-center justify-center">
             <Loader2 className="w-8 h-8 animate-spin text-gray-400" />
          </div>
        ) : (
          <div className="flex h-full overflow-hidden">
            {/* Sidebar (Room List) */}
            <div 
              style={{ width: SIDEBAR_WIDTH }} 
              className="flex-shrink-0 border-r bg-white z-40 shadow-[4px_0_6px_-4px_rgba(0,0,0,0.1)] flex flex-col"
            >
              <div className="h-[80px] border-b flex items-center px-4 font-bold text-gray-400 text-xs uppercase tracking-widest">
                Listing Details
              </div>
              <div className="flex-1 overflow-y-auto no-scrollbar">
                {filteredRooms.map(room => (
                  <div key={room.id} className="h-16 border-b px-4 flex items-center gap-3 hover:bg-gray-50 group transition-colors">
                    <div className="w-10 h-10 bg-gray-200 rounded-md overflow-hidden flex-shrink-0 flex items-center justify-center">
                       <Home className="w-5 h-5 text-gray-400" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="text-sm font-semibold truncate group-hover:text-[#FF385C] transition-colors">{room.name}</div>
                      <div className="text-[10px] text-gray-400 truncate uppercase tracking-tighter">{room.building} • {room.type}</div>
                    </div>
                    <a 
                      href={room.icalLink || '#'} 
                      target="_blank" 
                      rel="noopener noreferrer" 
                      className="opacity-0 group-hover:opacity-100 p-1.5 hover:bg-gray-200 rounded-full transition-all"
                    >
                       {AIRBNB_ICON}
                    </a>
                  </div>
                ))}
              </div>
            </div>

            {/* Timeline View */}
            <div 
              ref={scrollContainerRef}
              className="flex-1 overflow-auto flex flex-col no-scrollbar select-none"
            >
              {/* Timeline Header */}
              <div 
                style={{ width: days.length * DAY_COLUMN_WIDTH }} 
                className="h-[80px] border-b bg-white flex flex-col sticky top-0 z-30"
              >
                {/* Month labels */}
                <div className="flex h-1/2 border-b">
                  {/* Simplistic month rendering */}
                  {Array.from(new Set(days.map(d => format(d, 'MMM yyyy')))).map(monthStr => {
                    const firstDayIdx = days.findIndex(d => format(d, 'MMM yyyy') === monthStr);
                    const lastDayIdx = days.findLastIndex(d => format(d, 'MMM yyyy') === monthStr);
                    const span = lastDayIdx - firstDayIdx + 1;
                    return (
                      <div 
                        key={monthStr} 
                        style={{ width: span * DAY_COLUMN_WIDTH }} 
                        className="px-4 flex items-center text-xs font-bold text-gray-500 border-r"
                      >
                        {monthStr}
                      </div>
                    );
                  })}
                </div>
                {/* Day labels */}
                <div className="flex h-1/2">
                  {days.map(day => (
                    <div 
                      key={day.toString()} 
                      style={{ width: DAY_COLUMN_WIDTH }}
                      className={`flex-shrink-0 flex flex-col items-center justify-center text-[10px] border-r ${isWeekend(day) ? 'bg-gray-50' : ''} ${isSameDay(day, new Date()) ? 'bg-blue-50' : ''}`}
                    >
                      <span className="text-gray-400 font-medium uppercase">{format(day, 'EEE')}</span>
                      <span className={`font-bold mt-0.5 w-6 h-6 flex items-center justify-center rounded-full ${isSameDay(day, new Date()) ? 'bg-[#FF385C] text-white' : 'text-gray-700'}`}>
                        {format(day, 'd')}
                      </span>
                    </div>
                  ))}
                </div>
              </div>

              {/* Rows */}
              <div 
                className="flex-1 relative"
                style={{ width: days.length * DAY_COLUMN_WIDTH }}
              >
                {/* Vertical grid lines */}
                <div className="absolute inset-0 flex pointer-events-none">
                  {days.map(day => (
                    <div 
                      key={`grid-${day}`} 
                      style={{ width: DAY_COLUMN_WIDTH }} 
                      className={`h-full border-r ${isWeekend(day) ? 'bg-gray-50/50' : ''}`}
                    />
                  ))}
                </div>

                {/* Data Rows */}
                {filteredRooms.map(room => (
                  <div key={`row-${room.id}`} className="h-16 border-b relative group">
                    {/* Hover state row background */}
                    <div className="absolute inset-0 bg-gray-50/0 group-hover:bg-gray-50/50 transition-colors pointer-events-none" />

                    {/* Booking Blocks */}
                    {room.bookings.map((booking, idx) => {
                      const startDate = startOfDay(new Date(booking.start));
                      const endDate = startOfDay(new Date(booking.end));

                      // Check if booking is within current view
                      const viewStart = days[0];
                      const viewEnd = days[days.length - 1];

                      if (endDate < viewStart || startDate > viewEnd) return null;

                      const startOffset = Math.max(0, differenceInDays(startDate, viewStart));
                      const duration = differenceInDays(
                        endDate > viewEnd ? addDays(viewEnd, 1) : endDate, 
                        startDate < viewStart ? viewStart : startDate
                      );

                      if (duration <= 0) return null;

                      return (
                        <div 
                          key={`${room.id}-booking-${idx}`}
                          style={{
                            left: startOffset * DAY_COLUMN_WIDTH + 8,
                            width: duration * DAY_COLUMN_WIDTH - 16,
                            top: '12px',
                            height: '40px'
                          }}
                          className="absolute z-10 bg-[#008489] text-white rounded-full flex items-center px-4 text-xs font-medium shadow-sm cursor-pointer hover:bg-[#006C70] transition-colors overflow-hidden truncate whitespace-nowrap"
                        >
                          <span className="truncate">{booking.guestName || 'Reserved'}</span>
                        </div>
                      );
                    })}
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Footer / Status */}
      <footer className="border-t bg-white px-6 py-2 text-[11px] text-gray-400 flex justify-between items-center">
        <div>Showing {filteredRooms.length} of {rooms.length} listings</div>
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-[#008489]" /> Confirmed</div>
          <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-gray-200" /> Empty</div>
        </div>
      </footer>

      {/* Add Room Modal */}
      {isModalOpen && (
        <AddRoomModal 
          onClose={() => setIsModalOpen(false)} 
          onSuccess={() => {
            setIsModalOpen(false);
            loadData();
          }} 
        />
      )}
    </div>
  );
};

interface ModalProps {
  onClose: () => void;
  onSuccess: () => void;
}

const AddRoomModal: React.FC<ModalProps> = ({ onClose, onSuccess }) => {
  const [formData, setFormData] = useState({
    name: '',
    building: '',
    type: 'Studio',
    icalLink: ''
  });
  const [submitting, setSubmitting] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);
    const success = await addRoom(formData);
    if (success) {
      onSuccess();
    } else {
      alert('Failed to add room. Check API connection.');
      setSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="flex items-center justify-between p-6 border-b">
          <h2 className="text-xl font-bold">Add New Room</h2>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div className="space-y-1">
            <label className="text-xs font-bold text-gray-500 uppercase">Room Name</label>
            <input 
              required
              type="text" 
              placeholder="e.g. Avalon 301 - Ocean View"
              className="w-full border rounded-lg px-4 py-2.5 outline-none focus:ring-2 ring-[#FF385C]/20 focus:border-[#FF385C] transition-all"
              value={formData.name}
              onChange={(e) => setFormData({...formData, name: e.target.value})}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 uppercase">Building</label>
              <input 
                required
                type="text" 
                placeholder="e.g. Avalon"
                className="w-full border rounded-lg px-4 py-2.5 outline-none focus:ring-2 ring-[#FF385C]/20 focus:border-[#FF385C] transition-all"
                value={formData.building}
                onChange={(e) => setFormData({...formData, building: e.target.value})}
              />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 uppercase">Room Type</label>
              <select 
                className="w-full border rounded-lg px-4 py-2.5 outline-none focus:ring-2 ring-[#FF385C]/20 focus:border-[#FF385C] transition-all"
                value={formData.type}
                onChange={(e) => setFormData({...formData, type: e.target.value})}
              >
                <option value="Studio">Studio</option>
                <option value="1BR">1 Bedroom</option>
                <option value="2BR">2 Bedrooms</option>
                <option value="3BR">3 Bedrooms</option>
                <option value="Penthouse">Penthouse</option>
              </select>
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-xs font-bold text-gray-500 uppercase">Airbnb iCal Link</label>
            <div className="relative">
              <input 
                type="url" 
                placeholder="https://www.airbnb.com/calendar/ical/..."
                className="w-full border rounded-lg pl-4 pr-10 py-2.5 outline-none focus:ring-2 ring-[#FF385C]/20 focus:border-[#FF385C] transition-all"
                value={formData.icalLink}
                onChange={(e) => setFormData({...formData, icalLink: e.target.value})}
              />
              <div className="absolute right-3 top-1/2 -translate-y-1/2">
                <ExternalLink className="w-4 h-4 text-gray-400" />
              </div>
            </div>
            <p className="text-[10px] text-gray-400 mt-1">Sync your bookings automatically from Airbnb via iCal.</p>
          </div>

          <div className="pt-4 flex gap-3">
             <button 
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-3 border rounded-lg font-bold text-gray-700 hover:bg-gray-50 transition-colors"
             >
               Cancel
             </button>
             <button 
              disabled={submitting}
              type="submit"
              className="flex-[2] bg-[#FF385C] text-white px-4 py-3 rounded-lg font-bold hover:bg-[#E31C5F] transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
             >
               {submitting ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Save Room'}
             </button>
          </div>
        </form>
      </div>
    </div>
  );
}

