const SPREADSHEET_ID = SpreadsheetApp.getActiveSpreadsheet() ? SpreadsheetApp.getActiveSpreadsheet().getId() : "YOUR_SPREADSHEET_ID_HERE";
const SHEET_NAME = "Rooms";

function doGet(e) {
  try {
    const rooms = getRoomsData();
    return ContentService.createTextOutput(JSON.stringify({ status: "success", data: rooms }))
      .setMimeType(ContentService.MimeType.JSON);
  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: error.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

function doPost(e) {
  try {
    const params = JSON.parse(e.postData.contents);
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const sheet = ss.getSheetByName(SHEET_NAME) || ss.insertSheet(SHEET_NAME);

    // Kiểm tra và tạo tiêu đề nếu chưa có
    if (sheet.getLastRow() === 0) {
      sheet.appendRow(["ID", "Tên phòng", "Tòa nhà", "Loại", "Link iCal", "Link Listing"]);
    }

    const id = Utilities.getUuid();
    // Thêm ListingUrl vào cột thứ 6
    sheet.appendRow([id, params.name, params.building, params.type, params.icalLink, params.listingUrl || ""]);

    return ContentService.createTextOutput(JSON.stringify({ status: "success", id: id }))
      .setMimeType(ContentService.MimeType.JSON);
  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: error.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

function getRoomsData() {
  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  const sheet = ss.getSheetByName(SHEET_NAME);
  if (!sheet) return [];

  const data = sheet.getDataRange().getValues();
  const headers = data.shift();

  return data.map(row => {
    const room = {
      id: row[0],
      name: row[1],
      building: row[2],
      type: row[3],
      icalLink: row[4],
      listingUrl: row[5] || "",
      bookings: []
    };

    if (room.icalLink) {
      room.bookings = fetchAndParseIcal(room.icalLink);
    }

    return room;
  });
}

function fetchAndParseIcal(url) {
  try {
    const response = UrlFetchApp.fetch(url);
    const icalContent = response.getContentText();
    const events = [];

    const veventMatches = icalContent.split("BEGIN:VEVENT");
    veventMatches.shift(); 

    veventMatches.forEach(eventBlock => {
      const startMatch = eventBlock.match(/DTSTART(?:;VALUE=DATE)?:(\d{8}(?:T\d{6}Z?)?)/);
      const endMatch = eventBlock.match(/DTEND(?:;VALUE=DATE)?:(\d{8}(?:T\d{6}Z?)?)/);
      const summaryMatch = eventBlock.match(/SUMMARY:(.*)/);

      if (startMatch && endMatch) {
        events.push({
          start: formatDateString(startMatch[1]),
          end: formatDateString(endMatch[1]),
          guestName: summaryMatch ? summaryMatch[1].trim() : "Khách Airbnb"
        });
      }
    });

    return events;
  } catch (e) {
    console.error("Lỗi fetch iCal:", e);
    return [];
  }
}

function formatDateString(str) {
  const y = str.substring(0, 4);
  const m = str.substring(4, 6);
  const d = str.substring(6, 8);
  return `${y}-${m}-${d}`;
}

