import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  Plus, 
  Search, 
  ChevronLeft, 
  ChevronRight, 
  ExternalLink, 
  X,
  Loader2,
  Calendar as CalendarIcon,
  Home,
  Copy,
  Check,
  Save
} from 'lucide-react';
import { 
  format, 
  addDays, 
  startOfDay, 
  isSameDay, 
  differenceInDays, 
  eachDayOfInterval,
  isWeekend,
  isWithinInterval
} from 'date-fns';
import { vi } from 'date-fns/locale';
import { Room } from './types';
import { fetchRooms, addRoom, updateRoomPrice } from './services/api';
import { 
  AIRBNB_ICON, 
  CALENDAR_DAYS_COUNT, 
  DAY_COLUMN_WIDTH, 
  SIDEBAR_WIDTH 
} from './constants';

const App: React.FC = () => {
  const [rooms, setRooms] = useState<Room[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentDate, setCurrentDate] = useState(startOfDay(new Date()));
  const [filterBuilding, setFilterBuilding] = useState<string>('Tất cả');
  const [filterType, setFilterType] = useState<string>('Tất cả');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [copiedId, setCopiedId] = useState<string | null>(null);

  const scrollContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const data = await fetchRooms();
    setRooms(data);
    setLoading(false);
  };

  const days = useMemo(() => {
    return eachDayOfInterval({
      start: currentDate,
      end: addDays(currentDate, CALENDAR_DAYS_COUNT - 1)
    });
  }, [currentDate]);

  const buildings = useMemo(() => {
    const b = Array.from(new Set(rooms.map(r => r.building)));
    return ['Tất cả', ...b];
  }, [rooms]);

  const types = useMemo(() => {
    const t = Array.from(new Set(rooms.map(r => r.type)));
    return ['Tất cả', ...t];
  }, [rooms]);

  const filteredRooms = useMemo(() => {
    return rooms.filter(room => {
      const matchesBuilding = filterBuilding === 'Tất cả' || room.building === filterBuilding;
      const matchesType = filterType === 'Tất cả' || room.type === filterType;
      const matchesSearch = room.name.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesBuilding && matchesType && matchesSearch;
    });
  }, [rooms, filterBuilding, filterType, searchTerm]);

  const handleCopyLink = (url: string | undefined, id: string) => {
    if (!url) return;
    navigator.clipboard.writeText(url);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const handlePriceChange = async (roomId: string, date: string, price: string) => {
    // Cập nhật local state trước để UI mượt
    setRooms(prev => prev.map(r => {
      if (r.id === roomId) {
        return { ...r, prices: { ...r.prices, [date]: price } };
      }
      return r;
    }));
    // Lưu vào database
    await updateRoomPrice(roomId, date, price);
  };

  const isDayBooked = (room: Room, day: Date) => {
    return room.bookings.some(booking => {
      const start = startOfDay(new Date(booking.start));
      const end = startOfDay(new Date(booking.end));
      return isWithinInterval(day, { start, end: addDays(end, -1) });
    });
  };

  return (
    <div className="flex flex-col h-screen bg-white">
      {/* Header */}
      <header className="border-b px-6 py-3 flex items-center justify-between bg-white sticky top-0 z-50">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 text-[#FF385C] font-bold text-xl">
             <CalendarIcon className="w-6 h-6" />
             <span>Quản Lý Lịch & Giá</span>
          </div>
          <div className="ml-8 flex items-center gap-2 bg-gray-100 rounded-full px-4 py-2 border focus-within:ring-2 ring-gray-200 transition-all">
            <Search className="w-4 h-4 text-gray-500" />
            <input type="text" placeholder="Tìm phòng..." className="bg-transparent outline-none text-sm w-48" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
        </div>
        <button onClick={() => setIsModalOpen(true)} className="bg-[#FF385C] hover:bg-[#E31C5F] text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 shadow-sm transition-colors">
          <Plus className="w-4 h-4" /> Thêm Phòng
        </button>
      </header>

      {/* Filters */}
      <div className="px-6 py-3 border-b bg-white flex flex-wrap items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <select value={filterBuilding} onChange={(e) => setFilterBuilding(e.target.value)} className="border rounded-md px-2 py-1 text-sm bg-white outline-none">
            {buildings.map(b => <option key={b} value={b}>{b}</option>)}
          </select>
          <select value={filterType} onChange={(e) => setFilterType(e.target.value)} className="border rounded-md px-2 py-1 text-sm bg-white outline-none">
            {types.map(t => <option key={t} value={t}>{t}</option>)}
          </select>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setCurrentDate(prev => addDays(prev, -7))} className="p-2 hover:bg-gray-100 rounded-full border shadow-sm"><ChevronLeft className="w-4 h-4" /></button>
          <button onClick={() => setCurrentDate(startOfDay(new Date()))} className="px-4 py-1.5 border rounded-full text-sm font-medium hover:bg-gray-50">Hôm nay</button>
          <button onClick={() => setCurrentDate(prev => addDays(prev, 7))} className="p-2 hover:bg-gray-100 rounded-full border shadow-sm"><ChevronRight className="w-4 h-4" /></button>
          <div className="ml-2 font-semibold text-gray-700 capitalize">{format(days[0], 'MMMM yyyy', { locale: vi })}</div>
        </div>
      </div>

      {/* Multi-Calendar View */}
      <div className="flex-1 overflow-hidden relative flex flex-col">
        {loading ? <div className="flex-1 flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-gray-400" /></div> : (
          <div className="flex h-full overflow-hidden">
            {/* Sidebar */}
            <div style={{ width: SIDEBAR_WIDTH }} className="flex-shrink-0 border-r bg-white z-40 shadow-[4px_0_6px_-4px_rgba(0,0,0,0.1)] flex flex-col">
              <div className="h-[80px] border-b flex items-center px-4 font-bold text-gray-400 text-xs uppercase tracking-widest">Listing</div>
              <div className="flex-1 overflow-y-auto no-scrollbar">
                {filteredRooms.map(room => (
                  <div key={room.id} className="h-16 border-b px-4 flex items-center gap-3 hover:bg-gray-50 group">
                    <div className="w-10 h-10 bg-gray-200 rounded-md flex items-center justify-center flex-shrink-0"><Home className="w-5 h-5 text-gray-400" /></div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1">
                        <a href={room.listingUrl || '#'} target="_blank" rel="noopener noreferrer" className="text-sm font-semibold truncate hover:text-[#FF385C] hover:underline">{room.name}</a>
                        {room.listingUrl && (
                          <button onClick={() => handleCopyLink(room.listingUrl, room.id)} className="p-1 text-gray-400 hover:text-[#FF385C]">
                            {copiedId === room.id ? <Check className="w-3 h-3 text-green-500" /> : <Copy className="w-3 h-3" />}
                          </button>
                        )}
                      </div>
                      <div className="text-[10px] text-gray-400 uppercase">{room.building} • {room.type}</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Timeline */}
            <div ref={scrollContainerRef} className="flex-1 overflow-auto flex flex-col no-scrollbar select-none">
              {/* Header Timeline */}
              <div style={{ width: days.length * DAY_COLUMN_WIDTH }} className="h-[80px] border-b bg-white flex flex-col sticky top-0 z-30">
                <div className="flex h-1/2 border-b">
                  {Array.from(new Set(days.map(d => format(d, 'MMMM yyyy', { locale: vi })))).map(monthStr => {
                    const count = days.filter(d => format(d, 'MMMM yyyy', { locale: vi }) === monthStr).length;
                    return <div key={monthStr} style={{ width: count * DAY_COLUMN_WIDTH }} className="px-4 flex items-center text-xs font-bold text-gray-500 border-r capitalize">{monthStr}</div>;
                  })}
                </div>
                <div className="flex h-1/2">
                  {days.map(day => (
                    <div key={day.toString()} style={{ width: DAY_COLUMN_WIDTH }} className={`flex-shrink-0 flex flex-col items-center justify-center text-[10px] border-r ${isWeekend(day) ? 'bg-gray-50' : ''} ${isSameDay(day, new Date()) ? 'bg-blue-50' : ''}`}>
                      <span className="text-gray-400 font-medium uppercase">{format(day, 'EEE', { locale: vi })}</span>
                      <span className={`font-bold mt-0.5 w-6 h-6 flex items-center justify-center rounded-full ${isSameDay(day, new Date()) ? 'bg-[#FF385C] text-white' : 'text-gray-700'}`}>{format(day, 'd')}</span>
                    </div>
                  ))}
                </div>
              </div>

              {/* Rows with Inputs */}
              <div className="flex-1 relative" style={{ width: days.length * DAY_COLUMN_WIDTH }}>
                {filteredRooms.map(room => (
                  <div key={`row-${room.id}`} className="h-16 border-b relative flex items-center">
                    {days.map(day => {
                      const dateStr = format(day, 'yyyy-MM-dd');
                      const booked = isDayBooked(room, day);

                      return (
                        <div key={`${room.id}-${dateStr}`} style={{ width: DAY_COLUMN_WIDTH }} className="h-full border-r relative flex items-center justify-center">
                          {!booked && (
                            <input 
                              type="text"
                              placeholder="..."
                              defaultValue={room.prices[dateStr] || ''}
                              onBlur={(e) => handlePriceChange(room.id, dateStr, e.target.value)}
                              className="w-10 text-[10px] text-center bg-transparent border-none focus:ring-1 focus:ring-gray-200 rounded text-gray-600 font-medium"
                            />
                          )}
                        </div>
                      );
                    })}

                    {/* Booking Overlays */}
                    {room.bookings.map((booking, idx) => {
                      const startDate = startOfDay(new Date(booking.start));
                      const endDate = startOfDay(new Date(booking.end));
                      const viewStart = days[0];
                      const viewEnd = days[days.length - 1];
                      if (endDate < viewStart || startDate > viewEnd) return null;
                      const startOffset = Math.max(0, differenceInDays(startDate, viewStart));
                      const duration = differenceInDays(endDate > viewEnd ? addDays(viewEnd, 1) : endDate, startDate < viewStart ? viewStart : startDate);
                      if (duration <= 0) return null;
                      return (
                        <div key={`${room.id}-booking-${idx}`} style={{ left: startOffset * DAY_COLUMN_WIDTH + 4, width: duration * DAY_COLUMN_WIDTH - 8, top: '12px', height: '40px' }} className="absolute z-10 bg-[#008489] text-white rounded-lg flex items-center px-3 text-[11px] font-semibold shadow-sm truncate pointer-events-none">
                          <span className="truncate">{booking.guestName || 'Airbnb'}</span>
                        </div>
                      );
                    })}
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>

      <footer className="border-t bg-white px-6 py-2 text-[11px] text-gray-400 flex justify-between items-center">
        <div>Nhập giá trực tiếp vào các ô trống. Hệ thống sẽ tự động lưu.</div>
        <div className="flex items-center gap-4">
           <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-[#008489]" /> Đã đặt</div>
           <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full border border-gray-300" /> Trống (Nhập giá)</div>
        </div>
      </footer>

      {isModalOpen && <AddRoomModal onClose={() => setIsModalOpen(false)} onSuccess={() => { setIsModalOpen(false); loadData(); }} />}
    </div>
  );
};

