        <div className="flex items-center gap-2 flex-shrink-0">
          <span className="text-[10px] font-bold text-gray-400 uppercase">Tòa:</span>
          <select value={filterBuilding} onChange={e => setFilterBuilding(e.target.value)} className="text-xs border rounded px-2 py-1 outline-none">
            {buildings.map(b => <option key={b} value={b}>{b}</option>)}
          </select>
        </div>
        <div className="flex items-center gap-1 flex-shrink-0">
          <button onClick={() => setCurrentDate(prev => addDays(prev, -7))} className="p-1.5 hover:bg-gray-100 rounded-full border"><ChevronLeft className="w-4 h-4" /></button>
          <button onClick={() => setCurrentDate(startOfDay(new Date()))} className="px-3 py-1 text-xs font-bold border rounded-full hover:bg-gray-50">Hôm nay</button>
          <button onClick={() => setCurrentDate(prev => addDays(prev, 7))} className="p-1.5 hover:bg-gray-100 rounded-full border"><ChevronRight className="w-4 h-4" /></button>
          <span className="ml-2 text-xs font-bold text-gray-600 capitalize">{format(days[0], 'MMMM yyyy', { locale: vi })}</span>
        </div>
      </div>

      {/* Main Calendar Area */}
      <div className="flex-1 overflow-hidden flex relative">
        {loading ? <div className="flex-1 flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-[#FF385C]" /></div> : (
          <div className="flex h-full w-full overflow-hidden">
            {/* Sidebar Room Names */}
            <div style={{ width: SIDEBAR_WIDTH }} className="flex-shrink-0 border-r bg-white z-40 shadow-md">
              <div className="h-16 border-b flex items-center px-4 text-[10px] font-bold text-gray-400 uppercase tracking-widest">Danh sách phòng</div>
              <div className="overflow-y-auto no-scrollbar h-[calc(100%-64px)]">
                {filteredRooms.map(room => (
                  <div key={room.id} className="h-16 border-b px-3 flex items-center gap-2 hover:bg-gray-50 group transition-colors">
                    <div className="w-8 h-8 bg-gray-100 rounded-lg flex items-center justify-center text-gray-400 group-hover:text-[#FF385C]"><Home className="w-4 h-4" /></div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1">
                        <span className="text-xs font-bold truncate block">{room.name}</span>
                        {room.listingUrl && (
                          <button onClick={() => { navigator.clipboard.writeText(room.listingUrl!); setCopiedId(room.id); setTimeout(() => setCopiedId(null), 1000); }} className="p-1 text-gray-300 hover:text-blue-500">
                             {copiedId === room.id ? <Check className="w-3 h-3 text-green-500" /> : <Copy className="w-3 h-3" />}
                          </button>
                        )}
                      </div>
                      <div className="text-[9px] text-gray-400 uppercase leading-none">{room.building} • {room.type}</div>
                      {room.notes && <div className="text-[9px] text-orange-500 truncate mt-0.5"><Info className="w-2 h-2 inline mr-0.5" />{room.notes}</div>}
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Timeline Grid */}
            <div className="flex-1 overflow-auto no-scrollbar bg-gray-50">
              <div style={{ width: days.length * DAY_COLUMN_WIDTH }} className="h-full relative">
                {/* Header Timeline */}
                <div className="h-16 border-b bg-white flex flex-col sticky top-0 z-30">
                  <div className="flex h-1/2">
                    {days.map(day => (
                      <div key={day.toString()} style={{ width: DAY_COLUMN_WIDTH }} className={`flex-shrink-0 flex flex-col items-center justify-center text-[9px] border-r ${isWeekend(day) ? 'bg-gray-50' : ''} ${isSameDay(day, new Date()) ? 'bg-blue-50' : ''}`}>
                        <span className="text-gray-400 uppercase">{format(day, 'EEE', { locale: vi })}</span>
                        <span className={`font-bold mt-0.5 w-5 h-5 flex items-center justify-center rounded-full ${isSameDay(day, new Date()) ? 'bg-[#FF385C] text-white' : 'text-gray-700'}`}>{format(day, 'd')}</span>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Grid Rows */}
                {filteredRooms.map(room => (
                  <div key={`row-${room.id}`} className="h-16 border-b relative flex items-center bg-white">
                    {days.map(day => {
                      const dateStr = format(day, 'yyyy-MM-dd');
                      const booked = isDayBooked(room, day);
                      const price = room.prices?.[dateStr];
                      const isSelected = selectedSlot?.room.id === room.id && selectedSlot?.date === dateStr;

                      return (
                        <div 
                          key={`${room.id}-${dateStr}`} 
                          style={{ width: DAY_COLUMN_WIDTH }} 
                          onClick={() => !booked && setSelectedSlot({room, date: dateStr})}
                          className={`h-full border-r relative flex items-center justify-center transition-all cursor-pointer ${booked ? 'bg-gray-50/30' : 'hover:bg-blue-50/30'} ${isSelected ? 'ring-2 ring-inset ring-blue-400 z-20 bg-blue-50' : ''}`}
                        >
                          {!booked && (
                            <div className="flex flex-col items-center">
                              <input 
                                type="text"
                                placeholder="..."
                                defaultValue={price || ''}
                                onBlur={(e) => handlePriceChange(room.id, dateStr, e.target.value)}
                                className={`w-12 text-[10px] text-center bg-transparent border-none outline-none font-bold ${price ? 'text-green-600 bg-green-50/50 rounded-md py-0.5' : 'text-gray-300'}`}
                              />
                            </div>
                          )}
                        </div>
                      );
                    })}

                    {/* Bookings (Hidden Style) */}
                    {room.bookings.map((b, idx) => {
                      const startDate = startOfDay(new Date(b.start));
                      const endDate = startOfDay(new Date(b.end));
                      if (endDate < days[0] || startDate > days[days.length - 1]) return null;
                      const startOffset = Math.max(0, differenceInDays(startDate, days[0]));
                      const duration = differenceInDays(endDate > days[days.length - 1] ? addDays(days[days.length - 1], 1) : endDate, startDate < days[0] ? days[0] : startDate);
                      if (duration <= 0) return null;
                      return (
                        <div key={`${room.id}-b-${idx}`} style={{ left: startOffset * DAY_COLUMN_WIDTH + 4, width: duration * DAY_COLUMN_WIDTH - 8, top: '16px', height: '32px' }} className="absolute z-10 bg-gray-100 border border-gray-200 text-gray-400 rounded-md flex items-center px-2 text-[9px] font-medium shadow-none pointer-events-none opacity-60">
                          <span className="truncate">{b.guestName}</span>
                        </div>
                      );
                    })}
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Floating Action Bar (Sale optimized) */}
      {selectedSlot && (
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] max-w-md bg-white border border-gray-200 shadow-2xl rounded-2xl p-4 z-[60] animate-in slide-in-from-bottom-10 duration-300">
           <div className="flex items-center justify-between mb-3">
             <div>
               <h3 className="font-bold text-sm text-gray-800">{selectedSlot.room.name}</h3>
               <p className="text-[10px] text-gray-500 font-medium">Ngày: {format(new Date(selectedSlot.date), 'dd/MM/yyyy')} • <span className="text-green-600">Phòng trống</span></p>
             </div>
             <button onClick={() => setSelectedSlot(null)} className="p-1 hover:bg-gray-100 rounded-full"><X className="w-4 h-4 text-gray-400" /></button>
           </div>

           <div className="grid grid-cols-4 gap-2">
             <a href={`tel:${selectedSlot.room.contact}`} className="flex flex-col items-center gap-1 p-2 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-100 transition-colors">
               <Phone className="w-5 h-5" />
               <span className="text-[9px] font-bold">Gọi ngay</span>
             </a>
             <a href={`https://zalo.me/${selectedSlot.room.contact}`} target="_blank" className="flex flex-col items-center gap-1 p-2 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-colors">
               <MessageCircle className="w-5 h-5" />
               <span className="text-[9px] font-bold">Zalo</span>
             </a>
             <button onClick={() => copyListingInfo(selectedSlot.room, selectedSlot.date)} className="flex flex-col items-center gap-1 p-2 bg-gray-100 text-gray-700 rounded-xl hover:bg-gray-200 transition-colors">
               <Share2 className="w-5 h-5" />
               <span className="text-[9px] font-bold">Gửi khách</span>
             </button>
             <a href={selectedSlot.room.listingUrl} target="_blank" className="flex flex-col items-center gap-1 p-2 bg-pink-50 text-pink-600 rounded-xl hover:bg-pink-100 transition-colors">
               <ExternalLink className="w-5 h-5" />
               <span className="text-[9px] font-bold">Xem ảnh</span>
             </a>
           </div>

           {selectedSlot.room.notes && (
             <div className="mt-3 p-2 bg-orange-50 border border-orange-100 rounded-lg text-[10px] text-orange-700 italic">
               Lưu ý: {selectedSlot.room.notes}
             </div>
           )}
        </div>
      )}

      {isModalOpen && <AddRoomModal onClose={() => setIsModalOpen(false)} onSuccess={() => { setIsModalOpen(false); loadData(); }} />}
    </div>
  );
};

const AddRoomModal: React.FC<{ onClose: () => void; onSuccess: () => void; }> = ({ onClose, onSuccess }) => {
  const [formData, setFormData] = useState({ name: '', building: '', type: 'Studio', icalLink: '', listingUrl: '', contact: '', notes: '' });
  const [submitting, setSubmitting] = useState(false);
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);
    if (await addRoom(formData)) onSuccess();
    else { alert('Lỗi API'); setSubmitting(false); }
  };
  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden">
        <div className="p-6 border-b flex justify-between items-center"><h2 className="text-xl font-bold">Thêm Phòng Mới</h2><button onClick={onClose}><X className="w-5 h-5" /></button></div>
        <form onSubmit={handleSubmit} className="p-6 space-y-4 max-h-[80vh] overflow-y-auto">
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-gray-400 uppercase">Thông tin cơ bản</label>
            <input required placeholder="Tên phòng (Vd: Avalon 301)" className="w-full border rounded-xl px-4 py-3 text-sm focus:ring-2 ring-pink-100 outline-none" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
            <div className="grid grid-cols-2 gap-4 mt-2">
              <input required placeholder="Tòa nhà" className="w-full border rounded-xl px-4 py-3 text-sm focus:ring-2 ring-pink-100 outline-none" value={formData.building} onChange={e => setFormData({...formData, building: e.target.value})} />
              <select className="w-full border rounded-xl px-4 py-3 text-sm focus:ring-2 ring-pink-100 outline-none" value={formData.type} onChange={e => setFormData({...formData, type: e.target.value})}>
                <option value="Studio">Studio</option><option value="1BR">1 PN</option><option value="2BR">2 PN</option>
              </select>
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-gray-400 uppercase">Liên hệ & iCal</label>
            <input placeholder="SĐT Liên hệ / Zalo" className="w-full border rounded-xl px-4 py-3 text-sm focus:ring-2 ring-pink-100 outline-none" value={formData.contact} onChange={e => setFormData({...formData, contact: e.target.value})} />
            <input placeholder="Link Listing (Xem ảnh)" className="w-full border rounded-xl px-4 py-3 text-sm mt-2 focus:ring-2 ring-pink-100 outline-none" value={formData.listingUrl} onChange={e => setFormData({...formData, listingUrl: e.target.value})} />
            <input placeholder="Link iCal Airbnb" className="w-full border rounded-xl px-4 py-3 text-sm mt-2 focus:ring-2 ring-pink-100 outline-none" value={formData.icalLink} onChange={e => setFormData({...formData, icalLink: e.target.value})} />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-gray-400 uppercase">Ghi chú cho Sale</label>
            <textarea placeholder="Vd: Ưu tiên khách ở dài hạn, giảm giá cuối tuần..." className="w-full border rounded-xl px-4 py-3 text-sm h-20 outline-none focus:ring-2 ring-pink-100" value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} />
          </div>
          <div className="pt-4 flex gap-3">
            <button type="button" onClick={onClose} className="flex-1 px-4 py-3 border rounded-xl font-bold">Hủy</button>
            <button disabled={submitting} type="submit" className="flex-[2] bg-[#FF385C] text-white px-4 py-3 rounded-xl font-bold shadow-lg shadow-pink-200">
              {submitting ? 'Đang lưu...' : 'Lưu & Hoàn tất'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  Plus, Search, ChevronLeft, ChevronRight, ExternalLink, X, Loader2,
  Calendar as CalendarIcon, Home, Copy, Check, Phone, MessageCircle, Info
} from 'lucide-react';
import { 
  format, addDays, startOfDay, isSameDay, differenceInDays, 
  eachDayOfInterval, isWeekend, isWithinInterval
} from 'date-fns';
import { vi } from 'date-fns/locale';
import { Room } from './types';
import { fetchRooms, addRoom, updateRoomPrice } from './services/api';
import { CALENDAR_DAYS_COUNT, DAY_COLUMN_WIDTH, SIDEBAR_WIDTH } from './constants';

// Custom WhatsApp Icon
